// 인허가정보 내의 인허가명 팝업	
scwin.f_openApprPopUp = async function() {
    let apprGubun = lc_apprTypeCd.getValue();
    let apprNm = ed_apprNm.getValue();
    let rtnList = new Array();

    let data = {};
    data.apprGubun = apprGubun;
    data.apprTypeCd = apprGubun;
    data.apprNm = apprNm;
    data.closeTF= "T";

    let opt = {};
    opt.id = "smpPop";
    opt.title = "title";
    opt.width = "750";
    opt.height = "700";
    opt.popupName = "인허가명 조회";
    opt.modal = true;    

    if(apprGubun == ""){
        $c.gus.cfAlertMsg("인허가 종류를 먼저 선택해주시기 바랍니다.");
        return false;

    }else{
        rtnList = await $c.win.openPopup("/ui/cm/bc/permitmgnt/zz_950_01_01p.xml", opt, data);
        if (rtnList != null) {
            ed_apprNm.setValue(rtnList[1]);
            dma_results.set("apprCd", rtnList[0]);
        }
    }
};

