//-------------------------------------------------------------------------
// function name : f_openPopUp
// function desc : popup
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun)
    {
        case 1: //거래처
            let condition = "";
            udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc,
            pCode,pName,pClose,'5',null,'150,170',null,condition,null,null,null,null,null,pAllSearch,null);
        break;
        case 4: //회사코드
            udc_companyInfo2.cfCommonPopUp(scwin.udc_companyInfo2_callBackFunc,
            pCode,pName,pClose,null,null,null,null,null,null,null,null,null );
        break;
        case 5: //회사코드 조회조건용
            udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc,
            pCode,pName,pClose,null,null,null,null,null,null,null,null,null );
        break;

    default:
  	break;        
    }
};

scwin.udc_companyInfo_callBackFunc = function(rtnList) {
    if(rtnList != null ) {
        if (rtnList[0] == "N/A") return;
        ed_coCdS.setValue(rtnList[0]); // 코드
        ed_coNmS.setValue(rtnList[5]); // 회사명
        ed_coCdS.options.hidVal = rtnList[0];
    }else{
        ed_coCdS.setValue("");
        ed_coNmS.setValue("");
        ed_coCdS.options.hidVal = "";
    }

    // 관리부서 load
	if(lc_apprTypeCdS.getValue() != "" && ed_apprNmS.getValue() != "" && ed_coCdS.getValue() != ""){
		scwin.f_getRegDeptCombo();
	}
};

scwin.udc_companyInfo2_callBackFunc = function(rtnList) {
    if(rtnList != null ) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]); // 코드
        ed_coNm.setValue(rtnList[5]); // 회사명
        ed_coCd.options.hidVal = rtnList[0];
    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
    }
};

